// ============================================================================
// Types
// ============================================================================

interface Todo {
  id: number
  text: string
  completed: boolean
}

interface State {
  todos: Todo[]
  cursor: number
  nextId: number
  addTodo: (text: string) => void
  toggleTodo: () => void
  deleteTodo: () => void
  moveCursor: (delta: number) => void
}

// ============================================================================
// Store
// ============================================================================

const app = createApp<Record<string, unknown>, State>(
  // Store factory
  () => (set, get) => ({
    todos: [
      { id: 1, text: "Learn inkx-loop architecture", completed: true },
      { id: 2, text: "Build an app with createApp()", completed: false },
      { id: 3, text: "Ship to production", completed: false },
    ],
    cursor: 0,
    nextId: 4,

    addTodo: (text: string) =>
      set((s) => ({
        todos: [...s.todos, { id: s.nextId, text, completed: false }],
        nextId: s.nextId + 1,
      })),

    toggleTodo: () =>
      set((s) => ({
        todos: s.todos.map((t, i) => (i === s.cursor ? { ...t, completed: !t.completed } : t)),
      })),

    deleteTodo: () =>
      set((s) => {
        const newTodos = s.todos.filter((_, i) => i !== s.cursor)
        return {
          todos: newTodos,
          cursor: Math.min(s.cursor, newTodos.length - 1),
        }
      }),

    moveCursor: (delta: number) =>
      set((s) => ({
        cursor: Math.max(0, Math.min(s.cursor + delta, s.todos.length - 1)),
      })),
  }),

  // Event handlers
  {
    "term:key": (data: unknown, { get }: { get: () => State }) => {
      const { input: k, key } = data as {
        input: string
        key: { escape: boolean }
      }
      const state = get()
      if (key.escape) return "exit"
      switch (k) {
        case "j":
          state.moveCursor(1)
          break
        case "k":
          state.moveCursor(-1)
          break
        case "x":
          state.toggleTodo()
          break
        case "d":
          if (state.todos.length > 0) state.deleteTodo()
          break
        case "a":
          state.addTodo(`New todo ${state.nextId}`)
          break
        case "q":
          return "exit"
      }
    },
  },
)

